import{_ as a,o as s,c as i,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"85A. Trainee Enrolled Nurse Classifications","description":"","frontmatter":{"title":"85A. Trainee Enrolled Nurse Classifications","eba":"Nurses and Midwives 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/classification-staffing/85A-trainee-enrolled-nurse-classifications.md","filePath":"ebas/nurses-midwives/classification-staffing/85A-trainee-enrolled-nurse-classifications.md"}'),r={name:"ebas/nurses-midwives/classification-staffing/85A-trainee-enrolled-nurse-classifications.md"};function t(o,e,l,c,d,p){return s(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="_85a-trainee-enrolled-nurse-classifications" tabindex="-1">85A. Trainee Enrolled Nurse Classifications <a class="header-anchor" href="#_85a-trainee-enrolled-nurse-classifications" aria-label="Permalink to &quot;85A. Trainee Enrolled Nurse Classifications&quot;">​</a></h1><p><strong>85A.1</strong> Application The application of this clause is the same as that set out in <a href="/eba/ebas/nurses-midwives/classification-staffing/94-trainee-enrolled-nurses.html">clause 94.1</a>.</p><p><strong>85A.2</strong> Definitions</p><p><strong>(a)</strong> Approved Training has the meaning provided by <a href="/eba/ebas/nurses-midwives/classification-staffing/94-trainee-enrolled-nurses.html">clause 94.2</a>.</p><p><strong>(b)</strong> Enrolled Nurse has the meaning provided by <a href="/eba/ebas/allied-health/preliminary/4-definitions.html">clause 4</a>.</p><p><strong>(c)</strong> Trainee has the meaning provided by <a href="/eba/ebas/nurses-midwives/classification-staffing/94-trainee-enrolled-nurses.html">clause 94.2</a>.</p><p><strong>(d)</strong> Training Agreement means an agreement for a Traineeship made between an Employer and a Trainee which is registered with the relevant Victorian Training Authority.</p><p><strong>85A.3</strong> Trainee EN Year 1 Trainee EN Year 1 applies to a Trainee Enrolled Nurse in their first year of employment with the Employer.</p><p><strong>85A.4</strong> Trainee EN Year 2</p><p>Trainee EN Year 2 applies to a Trainee Enrolled Nurse in their second and subsequent years of employment with the Employer.</p>',10)])])}const u=a(r,[["render",t]]);export{h as __pageData,u as default};
